  function buildLexiconIndex(rows){
    const byUnit = new Map();
    for(const r of (rows||[])){
      const key = (r.unit_norm || String(r.unit||'').trim().toLowerCase());
      if(!key) continue;
      if(!byUnit.has(key)) byUnit.set(key, []);
      byUnit.get(key).push(r);
    }
    // Sort each bucket by unit_number descending (prefer higher Unit Number)
    for(const [k, arr] of byUnit.entries()){
      arr.sort((a,b)=> (b.unit_number ?? -1e12) - (a.unit_number ?? -1e12));
    }
    return byUnit;
  }

  const LEXICON_BY_UNIT = buildLexiconIndex(LEXICON_ROWS);

  const derivedLexiconRowsCache = { v4: null, v5: null };
  const derivedLexiconByUnitCache = { v4: null, v5: null };
  const richLexiconByUnitCache = { v4: null, v5: null };

  function getAvailableBaseLexiconSources(){
    const out = [{value:'legacy', label:'Legacy'}];
    if(typeof LEXICON_V4_ROWS !== 'undefined' && Array.isArray(LEXICON_V4_ROWS) && LEXICON_V4_ROWS.length){
      out.push({value:'v4', label:'V4'});
    }
    if(typeof LEXICON_V5_ROWS !== 'undefined' && Array.isArray(LEXICON_V5_ROWS) && LEXICON_V5_ROWS.length){
      out.push({value:'v5', label:'V5'});
    }
    return out;
  }

  function getAvailableRichLexiconSources(){
    const out = [];
    if(typeof LEXICON_V4_ROWS !== 'undefined' && Array.isArray(LEXICON_V4_ROWS) && LEXICON_V4_ROWS.length){
      out.push({value:'v4', label:'V4'});
    }
    if(typeof LEXICON_V5_ROWS !== 'undefined' && Array.isArray(LEXICON_V5_ROWS) && LEXICON_V5_ROWS.length){
      out.push({value:'v5', label:'V5'});
    }
    if(!out.length){
      out.push({value:'v4', label:'V4'});
    }
    return out;
  }

  function normalizeBaseLexiconSource(source){
    const value = String(source || '').trim().toLowerCase();
    const available = new Set(getAvailableBaseLexiconSources().map(x => x.value));
    if(available.has(value)) return value;
    if(available.has('v4')) return 'v4';
    return 'legacy';
  }

  function normalizeRichLexiconSource(source){
    const value = String(source || '').trim().toLowerCase();
    const available = getAvailableRichLexiconSources().map(x => x.value);
    if(available.includes(value)) return value;
    if(available.includes('v4')) return 'v4';
    if(available.includes('v5')) return 'v5';
    return 'v4';
  }

  function getBaseLexiconSourcePreference(){
    return normalizeBaseLexiconSource(loadFromStorage(STORAGE_KEYS.lexiconSource));
  }

  function setBaseLexiconSourcePreference(source){
    const next = normalizeBaseLexiconSource(source);
    saveToStorage(STORAGE_KEYS.lexiconSource, next);
    return next;
  }

  function getRichLexiconSourcePreference(){
    return normalizeRichLexiconSource(loadFromStorage(STORAGE_KEYS.richLexiconSource));
  }

  function setRichLexiconSourcePreference(source){
    const next = normalizeRichLexiconSource(source);
    saveToStorage(STORAGE_KEYS.richLexiconSource, next);
    return next;
  }

  function buildRichLexiconIndex(rows){
    const byUnit = new Map();
    for(const r of (rows || [])){
      const key = (r.unit_norm || String(r.unit || '').trim().toLowerCase());
      if(!key) continue;
      if(!byUnit.has(key)) byUnit.set(key, []);
      byUnit.get(key).push(r);
    }
    for(const arr of byUnit.values()){
      arr.sort((a, b)=> (Number(b.segment_id || 0) - Number(a.segment_id || 0)));
    }
    return byUnit;
  }

  function getRichLexiconRowsForSource(source){
    const next = normalizeRichLexiconSource(source);
    if(next === 'v5' && typeof LEXICON_V5_ROWS !== 'undefined' && Array.isArray(LEXICON_V5_ROWS) && LEXICON_V5_ROWS.length){
      return LEXICON_V5_ROWS;
    }
    if(typeof LEXICON_V4_ROWS !== 'undefined' && Array.isArray(LEXICON_V4_ROWS) && LEXICON_V4_ROWS.length){
      return LEXICON_V4_ROWS;
    }
    if(typeof LEXICON_V5_ROWS !== 'undefined' && Array.isArray(LEXICON_V5_ROWS) && LEXICON_V5_ROWS.length){
      return LEXICON_V5_ROWS;
    }
    return [];
  }

  function getRichLexiconRows(){
    return getRichLexiconRowsForSource(getRichLexiconSourcePreference());
  }

  function getRichLexiconIndex(){
    const source = normalizeRichLexiconSource(getRichLexiconSourcePreference());
    if(!richLexiconByUnitCache[source]){
      richLexiconByUnitCache[source] = buildRichLexiconIndex(getRichLexiconRowsForSource(source));
    }
    return richLexiconByUnitCache[source];
  }

  function getDerivedRichLexiconRows(source){
    const next = normalizeRichLexiconSource(source);
    if(!derivedLexiconRowsCache[next]){
      derivedLexiconRowsCache[next] = getRichLexiconRowsForSource(next).map(r => ({
        unit: r.unit,
        unit_norm: r.unit_norm,
        ipa: r.ipa,
        unit_number: r.segment_id
      }));
    }
    return derivedLexiconRowsCache[next];
  }

  function getPreferredLexiconRows(){
    const source = getBaseLexiconSourcePreference();
    if(source === 'legacy') return LEXICON_ROWS;
    return getDerivedRichLexiconRows(source);
  }

  function getLexiconIndexForSource(source){
    const next = normalizeBaseLexiconSource(source);
    if(next === 'legacy') return LEXICON_BY_UNIT;
    const richSource = normalizeRichLexiconSource(next);
    if(!derivedLexiconByUnitCache[richSource]){
      derivedLexiconByUnitCache[richSource] = buildLexiconIndex(getDerivedRichLexiconRows(richSource));
    }
    return derivedLexiconByUnitCache[richSource];
  }

  function getPreferredLexiconIndex(){
    return getLexiconIndexForSource(getBaseLexiconSourcePreference());
  }

  function buildLexiconSourceControl(kind, onChange, ariaLabel){
    const useRich = kind === 'rich';
    const current = useRich ? getRichLexiconSourcePreference() : getBaseLexiconSourcePreference();
    const setter = useRich ? setRichLexiconSourcePreference : setBaseLexiconSourcePreference;
    const opts = useRich ? getAvailableRichLexiconSources() : getAvailableBaseLexiconSources();
    const wrap = el('label', {class:'checkbox'});
    wrap.appendChild(el('span', {class:'muted'}, ['Lexicon']));
    const select = el('select', {
      class:'btn',
      title:'Lexicon source',
      'aria-label': ariaLabel || (useRich ? 'Rich lexicon source' : 'Lexicon source')
    });
    select.style.padding = '8px 10px';
    select.style.borderRadius = '10px';
    select.style.background = 'var(--surfaceStrong)';
    select.style.border = '1px solid var(--border)';
    select.style.color = 'var(--text)';
    for(const opt of opts){
      const option = el('option', {value: opt.value}, [opt.label]);
      if(opt.value === current) option.selected = true;
      select.appendChild(option);
    }
    select.addEventListener('change', ()=>{
      setter(select.value);
      if(typeof onChange === 'function') onChange(select.value);
    });
    wrap.appendChild(select);
    return {wrap, select};
  }

  function getLexiconMatches(unit){
    const key = normalizeWord(unit);
    return getPreferredLexiconIndex().get(key) || [];
  }

  function getDetectLexiconMatches(unit){
    const key = normalizeWord(unit);
    if(!key) return [];
    const out = [];
    const seen = new Set();
    for(const source of getAvailableBaseLexiconSources()){
      const matches = getLexiconIndexForSource(source.value).get(key) || [];
      for(const match of matches){
        const dedupeKey = [
          source.value,
          String(match.segment_id ?? match.unit_number ?? ''),
          String(match.unit_norm ?? normalizeWord(match.unit || '')),
          String(match.ipa ?? '')
        ].join('::');
        if(seen.has(dedupeKey)) continue;
        seen.add(dedupeKey);
        out.push(match);
      }
    }
    return out;
  }

  function chooseDefaultMatch(matches){
    if(!matches || !matches.length) return null;
    return matches[0];
  }

  function joinIpa(parts, mode){
    const segs = (parts||[]).map(x=>String(x||'')).filter(Boolean);
    if(!segs.length) return '';
    if(mode === 'none') return segs.join('');
    if(mode === 'dot') return segs.join('.');
    return segs.join(' '); // default: space
  }

 
